class Solution:
    def countSpecialSubsequences(self, nums):
        MOD = 10 ** 9 + 7
        ways0 = ways01 = ways012 = 0
        for x in nums:
            if x == 0:
                ways0 = (2 * ways0 + 1) % MOD
            elif x == 1:
                ways01 = (2 * ways01 + ways0) % MOD
            else:
                ways012 = (2 * ways012 + ways01) % MOD
        return ways012 % MOD

solutions.python:
class Solution:
    def countSpecialSubsequences(self, nums):
        MOD = 10 ** 9 + 7
        dp = [0, 0, 0]
        for x in nums:
            if x == 0:
                dp[0] = (dp[0] * 2 + 1) % MOD
            elif x == 1:
                dp[1] = (dp[1] * 2 + dp[0]) % MOD
            else:
                dp[2] = (dp[2] * 2 + dp[1]) % MOD
        return dp[2]

