var countSpecialSubsequences = function(nums) {
    const MOD = 1000000007n;
    let d0 = 0n, d1 = 0n, d2 = 0n;
    for (const x of nums) {
        if (x === 0) d0 = (d0 * 2n + 1n) % MOD;
        else if (x === 1) d1 = (d1 * 2n + d0) % MOD;
        else d2 = (d2 * 2n + d1) % MOD;
    }
    return Number(d2 % MOD);
};
